     1→'use client';
     2→
     3→import { useState, useCallback } from 'react';
     4→import Link from 'next/link';
     5→import HorizontalScroll from './HorizontalScroll';
     6→import CoverImage from './CoverImage';
     7→import { useLanguage } from './LanguageProvider';
     8→import { shuffle, shuffleSeeded } from '@/lib/shuffle';
     9→import { getPostUrl } from '@/lib/urls';
    10→
    11→export interface SeriesItem {
    12→  name: string;
    13→  title: string;
    14→  excerpt: string;
    15→  coverImage?: string;
    16→  url: string;
    17→  postCount: number;
    18→  topPosts: { slug: string; title: string }[];
    19→}
    20→
    21→interface CuratedSeriesSectionProps {
    22→  allSeries: SeriesItem[];
    23→  maxItems: number;
    24→  scrollThreshold: number;
    25→}
    26→
    27→export default function CuratedSeriesSection({ allSeries, maxItems, scrollThreshold }: CuratedSeriesSectionProps) {
    28→  const { t } = useLanguage();
    29→  // Use a daily seed so SSR and client hydration agree on the initial order,
    30→  // preventing a visible reshuffle flash on page load.
    31→  const [displayed, setDisplayed] = useState(() => {
    32→    const dailySeed = Math.floor(Date.now() / 86400000);
    33→    return shuffleSeeded(allSeries, dailySeed).slice(0, maxItems);
    34→  });
    35→
    36→  const handleShuffle = useCallback(() => {
    37→    setDisplayed(shuffle(allSeries).slice(0, maxItems));
    38→  }, [allSeries, maxItems]);
    39→
    40→  if (allSeries.length === 0) return null;
    41→
    42→  return (
    43→    <section id="featured-series" className="mb-12 sm:mb-24">
    44→      <div className="flex items-center justify-between mb-8">
    45→        <h2 className="text-2xl sm:text-3xl font-serif font-bold text-heading">{t('curated_series')}</h2>
    46→        <div className="flex items-center gap-4">
    47→          {allSeries.length > maxItems && (
    48→            <button
    49→              onClick={handleShuffle}
    50→              className="text-sm text-muted hover:text-accent transition-colors focus:outline-none"
    51→              aria-label={t('shuffle_series')}
    52→              title={t('shuffle_series')}
    53→            >
    54→              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={1.5}>
    55→                <path strokeLinecap="round" strokeLinejoin="round" d="M16 3h5v5M4 20L21 3M21 16v5h-5M15 15l6 6M4 4l5 5" />
    56→              </svg>
    57→            </button>
    58→          )}
    59→          <Link href="/series" className="text-sm text-muted hover:text-accent transition-colors no-underline">
    60→            {t('all_series')} →
    61→          </Link>
    62→        </div>
    63→      </div>
    64→      <HorizontalScroll
    65→        itemCount={displayed.length}
    66→        scrollThreshold={scrollThreshold}
    67→      >
    68→        <div className={`flex gap-8 ${displayed.length > scrollThreshold ? 'pb-4' : ''}`}>
    69→          {displayed.map((series, idx) => (
    70→            <div
    71→              key={series.name}
    72→              className={`card-base group flex flex-col p-0 overflow-hidden snap-start ${
    73→                displayed.length > scrollThreshold
    74→                  ? 'w-[85vw] md:w-[calc(50%-1rem)] flex-shrink-0'
    75→                  : 'flex-1 md:max-w-[calc(50%-1rem)]'
    76→              }`}
    77→            >
    78→              <Link href={series.url} className="relative h-44 w-full overflow-hidden bg-muted/10 block focus:outline-none focus:ring-2 focus:ring-accent/50 focus:ring-inset">
    79→                <CoverImage
    80→                  src={series.coverImage}
    81→                  title={series.title}
    82→                  slug={series.name}
    83→                  className="h-full w-full object-cover transition-transform duration-700 group-hover:scale-105"
    84→                  loading={idx === 0 ? 'eager' : undefined}
    85→                />
    86→                <div className="absolute inset-0 bg-black/10 group-hover:bg-transparent transition-colors duration-500" />
    87→              </Link>
    88→              <div className="p-6 flex flex-col flex-1 relative z-10">
    89→                <div className="mb-4">
    90→                  <span className="badge-accent">
    91→                    {series.postCount} {t('parts')}
    92→                  </span>
    93→                </div>
