'use client';

import { useRef, useState, useEffect, ReactNode, useCallback } from 'react';

interface HorizontalScrollProps {
  children: ReactNode;
  itemCount: number;
  scrollThreshold: number;
  className?: string;
}

export default function HorizontalScroll({
  children,
  itemCount,
  scrollThreshold,
  className = ''
}: HorizontalScrollProps) {
  const scrollRef = useRef<HTMLDivElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const [canScrollLeft, setCanScrollLeft] = useState(false);
  const [canScrollRight, setCanScrollRight] = useState(false);

  const shouldShowArrows = itemCount > scrollThreshold;

  const updateScrollState = useCallback(() => {
    if (!scrollRef.current) return;
    const { scrollLeft, scrollWidth, clientWidth } = scrollRef.current;
    setCanScrollLeft(scrollLeft > 0);
    setCanScrollRight(scrollLeft < scrollWidth - clientWidth - 1);
  }, []);

  useEffect(() => {
    updateScrollState();
    const container = scrollRef.current;
    if (container) {
      container.addEventListener('scroll', updateScrollState);
      window.addEventListener('resize', updateScrollState);
    }
    return () => {
      if (container) {
        container.removeEventListener('scroll', updateScrollState);
      }
      window.removeEventListener('resize', updateScrollState);
    };
  }, [updateScrollState]);

  const scroll = useCallback((direction: 'left' | 'right') => {
    if (!scrollRef.current) return;
    const container = scrollRef.current;
    const scrollAmount = container.clientWidth * 0.8;
    container.scrollBy({
      left: direction === 'left' ? -scrollAmount : scrollAmount,
      behavior: 'smooth'
    });
  }, []);

  // Handle keyboard navigation
  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'ArrowLeft' && canScrollLeft) {
      e.preventDefault();
      scroll('left');
    } else if (e.key === 'ArrowRight' && canScrollRight) {
      e.preventDefault();
      scroll('right');
    }
  }, [canScrollLeft, canScrollRight, scroll]);

  if (!shouldShowArrows) {
    return (
      <div
        className={`overflow-x-auto scrollbar-hide scroll-smooth snap-x snap-mandatory ${className}`}
        style={{ scrollSnapType: 'x mandatory' }}
      >
        {children}
      </div>
    );
  }

  return (
    <div
      ref={containerRef}
      className="relative group/scroll overflow-visible"
      onKeyDown={handleKeyDown}
      tabIndex={0}
      role="region"
      aria-label="Scrollable content"
    >
      {/* Left Arrow - positioned outside content in margin area */}
      <button
