'use client';

import { useState, useCallback } from 'react';
import Link from 'next/link';
import CoverImage from './CoverImage';
import HorizontalScroll from './HorizontalScroll';
import { useLanguage } from './LanguageProvider';
import { shuffle, shuffleSeeded } from '@/lib/shuffle';
import { getBooksListUrl, getBookUrl, getBookChapterUrl } from '@/lib/urls';

export interface BookItem {
  slug: string;
  title: string;
  excerpt?: string;
  coverImage?: string;
  authors: string[];
  chapterCount: number;
  firstChapter?: string;
}

interface SelectedBooksSectionProps {
  books: BookItem[];
  maxItems?: number;
}

export default function SelectedBooksSection({ books, maxItems = 4 }: SelectedBooksSectionProps) {
  const { t } = useLanguage();
  const [displayed, setDisplayed] = useState(() => {
    const dailySeed = Math.floor(Date.now() / 86400000);
    return shuffleSeeded(books, dailySeed).slice(0, maxItems);
  });

  const handleShuffle = useCallback(() => {
    setDisplayed(shuffle(books).slice(0, maxItems));
  }, [books, maxItems]);

  if (books.length === 0) return null;

  return (
    <section id="featured-books" className="mb-12 sm:mb-24">
      <div className="flex items-center justify-between mb-8">
        <h2 className="text-2xl sm:text-3xl font-serif font-bold text-heading">{t('selected_books')}</h2>
        <div className="flex items-center gap-4">
          {books.length > maxItems && (
            <button
              onClick={handleShuffle}
              className="text-sm text-muted hover:text-accent transition-colors focus:outline-none"
              aria-label={t('shuffle_series')}
              title={t('shuffle_series')}
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24" strokeWidth={1.5}>
                <path strokeLinecap="round" strokeLinejoin="round" d="M16 3h5v5M4 20L21 3M21 16v5h-5M15 15l6 6M4 4l5 5" />
              </svg>
            </button>
          )}
          <Link href={getBooksListUrl()} className="text-sm text-muted hover:text-accent transition-colors no-underline">
            {t('all_books')} →
          </Link>
        </div>
      </div>
      <HorizontalScroll>
        <div className={`flex gap-8 ${displayed.length > 1 ? 'pb-4' : ''}`}>
          {displayed.map((book, idx) => (
            <div
              key={book.slug}
              className={`card-base group flex flex-col p-0 overflow-hidden snap-start ${
                displayed.length > 1
                  ? 'w-[85vw] md:w-[calc(50%-1rem)] flex-shrink-0'
                  : 'flex-1 md:max-w-[calc(50%-1rem)]'
              }`}
            >
              <Link href={getBookUrl(book.slug)} className="relative h-44 w-full overflow-hidden bg-muted/10 block focus:outline-none focus:ring-2 focus:ring-accent/50 focus:ring-inset">
                <CoverImage
                  src={book.coverImage}
                  title={book.title}
                  slug={book.slug}
                  className="h-full w-full object-cover transition-transform duration-700 group-hover:scale-105"
                  loading={idx === 0 ? 'eager' : undefined}
                />
                <div className="absolute inset-0 bg-black/10 group-hover:bg-transparent transition-colors duration-500" />
              </Link>
              <div className="p-6 flex flex-col flex-1">
                <div className="mb-4">
                  <span className="badge-accent">
                    {book.chapterCount} {t('chapters_count')}
                  </span>
                </div>
                <h3 className="mb-2 font-serif text-2xl font-bold text-heading group-hover:text-accent transition-colors line-clamp-2">
                  <Link href={getBookUrl(book.slug)} className="no-underline focus:outline-none focus:text-accent">
                    {book.title}
                  </Link>
                </h3>
                {book.authors.length > 0 && (
                  <p className="text-xs text-muted mb-3">
                    {t('written_by')} {book.authors.slice(0, 3).join(', ')}
                  </p>
                )}
                {book.excerpt && (
                  <p className="mb-6 text-muted font-serif italic line-clamp-2 text-base">
                    {book.excerpt}
                  </p>
                )}
                {book.firstChapter && (
                  <div className="mt-auto pt-6 border-t border-muted/10">
                    <Link
                      href={getBookChapterUrl(book.slug, book.firstChapter)}
                      className="text-sm font-sans font-bold text-accent flex items-center gap-1.5 no-underline hover:gap-2.5 transition-all"
                    >
                      {t('start_reading')}
                      <svg className="w-4 h-4" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}>
                        <path strokeLinecap="round" strokeLinejoin="round" d="M9 5l7 7-7 7" />
                      </svg>
                    </Link>
                  </div>
                )}
              </div>
            </div>
          ))}
        </div>
      </HorizontalScroll>
    </section>
  );
}

'use client';

import Link from 'next/link';
import { siteConfig } from '../../site.config';
import { useLanguage } from '@/components/LanguageProvider';
import { resolveLocaleValue } from '@/lib/i18n';
import { TranslationKey } from '@/i18n/translations';
import LanguageSwitch from './LanguageSwitch';

export default function Footer() {
  const { t, language } = useLanguage();

  return (
    <footer className="bg-muted/5 border-t border-muted/10 mt-auto">
      <div className="max-w-6xl mx-auto px-6 py-10 lg:py-16">
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-8 lg:gap-12 mb-10 lg:mb-12">
          {/* Brand */}
          <div className="col-span-2 lg:col-span-2">
            <Link href="/" className="flex items-center justify-center lg:justify-start gap-2 mb-4 group no-underline">
              <svg
                viewBox="0 0 32 32"
                className="w-6 h-6 text-accent group-hover:rotate-12 transition-transform duration-300"
                fill="none"
                stroke="currentColor"
                strokeWidth="2"
                strokeLinecap="round"
                strokeLinejoin="round"
                aria-hidden="true"
              >
                <path d="M16 4 L7 28" />
                <path d="M16 4 L25 28" />
                <path d="M11.5 18 H 20.5" />
                <path d="M20.5 18 Q 26 14 26 8 Q 23 12 20.5 18" fill="currentColor" stroke="none" />
              </svg>
              <span className="font-serif font-bold text-lg text-heading">{resolveLocaleValue(siteConfig.title, language)}</span>
            </Link>
            <p className="text-sm text-muted leading-relaxed max-w-sm text-center lg:text-left">
              {resolveLocaleValue(siteConfig.description, language)}
            </p>
          </div>

          {/* Navigation */}
          <div className="text-center lg:text-left">
            <h4 className="font-sans font-bold text-xs uppercase tracking-widest text-muted/80 mb-6">{t('explore')}</h4>
            <ul className="space-y-3 text-sm">
              {[...(siteConfig.footer?.explore ?? [])].sort((a, b) => a.weight - b.weight).map((item) => {
                const key = item.name.toLowerCase() as TranslationKey;
                const translated = t(key);
                const label = translated !== key ? translated : item.name;
                return (
                  <li key={item.url}>
                    <Link href={item.url} className="text-foreground/80 hover:text-accent transition-colors no-underline">
                      {label}
                    </Link>
                  </li>
                );
              })}
            </ul>
          </div>

          {/* Connect */}
          <div className="text-center lg:text-left">
            <h4 className="font-sans font-bold text-xs uppercase tracking-widest text-muted/80 mb-6">{t('connect')}</h4>
            <ul className="space-y-3 text-sm">
              {[...(siteConfig.footer?.connect ?? [])].sort((a, b) => a.weight - b.weight).map((item) => {
                const isExternal = item.external || item.url.startsWith('http');
                const key = item.name.toLowerCase() as TranslationKey;
                const translated = t(key);
                const label = translated !== key ? translated : item.name;
                const className = "text-foreground/80 hover:text-accent transition-colors no-underline flex items-center justify-center lg:justify-start gap-2";
                return (
                  <li key={item.url}>
                    {isExternal ? (
                      <a href={item.url} target="_blank" rel="noopener noreferrer" className={className}>
                        {label}
                      </a>
                    ) : (
                      <Link href={item.url} className={className}>
                        {label}
                      </Link>
                    )}
                  </li>
                );
              })}
            </ul>
          </div>
        </div>

        {/* Bottom Bar */}
        <div className="pt-8 border-t border-muted/10 flex flex-col md:flex-row justify-between items-center gap-4 text-xs text-muted">
          <span>{resolveLocaleValue(siteConfig.footerText, language)}</span>
          <div className="flex flex-wrap items-center gap-x-6 gap-y-2">
             {siteConfig.i18n.enabled !== false && siteConfig.i18n.locales.length >= 2 && (
               <>
                 <LanguageSwitch variant="text" />
                 <span className="opacity-20">|</span>
               </>
             )}
             <Link href="/privacy" className="hover:text-foreground transition-colors no-underline">{t('privacy')}</Link>
             {siteConfig.footer?.bottomLinks?.map((item, index) => {
               const label = resolveLocaleValue(item.text, language);
               const isInternal = item.url?.startsWith('/');
               return (
                 <span key={`${index}:${item.url ?? label}`} className="flex items-center gap-x-6">
                   <span className="opacity-20">|</span>
                   {item.url ? (
                     isInternal ? (
                       <Link href={item.url} className="hover:text-foreground transition-colors no-underline">{label}</Link>
                     ) : (
                       <a href={item.url} target="_blank" rel="noopener noreferrer" className="hover:text-foreground transition-colors no-underline">{label}</a>
                     )
                   ) : (
                     <span>{label}</span>
                   )}
                 </span>
               );
             })}
             {siteConfig.footer?.builtWith?.show && (() => {
               const cfg = siteConfig.footer.builtWith;
               const label = cfg.text ? resolveLocaleValue(cfg.text, language) : t('built_with');
               return (
                 <>
                   <span className="opacity-20">|</span>
                   <a href={cfg.url ?? 'https://github.com/hutusi/amytis'} target="_blank" rel="noreferrer" className="hover:text-foreground transition-colors no-underline">
                     {label}
                   </a>
                 </>
               );
             })()}
          </div>
        </div>
      </div>
    </footer>
  );
}
